6	
7	------------------------------------------------------------------------------
8	-- Libraries
9	------------------------------------------------------------------------------
10	library ieee;
11		use ieee.std_logic_1164.all;
12		use ieee.numeric_std.all;
13		
14	library std;
15		use std.textio.all;
16	
17	library work;
18		use work.psi_tb_txt_util.all;
19		use work.psi_tb_axi_pkg.all;
20		use work.definitions_pkg.all;
21		use work.psi_tb_compare_pkg.all;
22		use work.psi_common_math_pkg.all;
23		use work.psi_common_logic_pkg.all;
24	
25	entity top_tb is
26	end entity top_tb;
27	
28	architecture sim of top_tb is
29	
30		-------------------------------------------------------------------------
31		-- AXI Definition
32		-------------------------------------------------------------------------
33		constant ID_WIDTH 		: integer 	:= 1;
34		constant ADDR_WIDTH 	: integer	:= 8;
35		constant USER_WIDTH		: integer	:= 1;
36		constant DATA_WIDTH		: integer	:= 32;
37		constant BYTE_WIDTH		: integer	:= DATA_WIDTH/8;
38		
39		subtype ID_RANGE is natural range ID_WIDTH-1 downto 0;
40		subtype ADDR_RANGE is natural range ADDR_WIDTH-1 downto 0;
41		subtype USER_RANGE is natural range USER_WIDTH-1 downto 0;
42		subtype DATA_RANGE is natural range DATA_WIDTH-1 downto 0;
43		subtype BYTE_RANGE is natural range BYTE_WIDTH-1 downto 0;
44		
45		signal axi_ms : axi_ms_r (	arid(ID_RANGE), awid(ID_RANGE),
46									araddr(ADDR_RANGE), awaddr(ADDR_RANGE),
47									aruser(USER_RANGE), awuser(USER_RANGE), wuser(USER_RANGE),
48									wdata(DATA_RANGE),
49									wstrb(BYTE_RANGE));
50		
51		signal axi_sm : axi_sm_r (	rid(ID_RANGE), bid(ID_RANGE),
52									ruser(USER_RANGE), buser(USER_RANGE),
53									rdata(DATA_RANGE));
54	
55		-------------------------------------------------------------------------
56		-- TB Defnitions
57		-------------------------------------------------------------------------
58		constant	ClockFrequencyAxi_c	: real		:= 125.0e6;							-- Use slow clocks to speed up simulation
59		constant	ClockPeriodAxi_c	: time		:= (1 sec)/ClockFrequencyAxi_c;
60		constant 	SlaveCnt_c			: integer	:= 3;
61		
62		signal 		TbRunning			: boolean 	:= True;
63		signal		SlaveTx				: std_logic_vector(7 downto 0)	:= (others => '0');
64		signal		ExpectedSlaveRx		: std_logic_vector(7 downto 0)	:= (others => '0');
65		signal 		SlaveNr				: integer						:= 0;
66	
67		
68		-------------------------------------------------------------------------
69		-- Interface Signals
70		-------------------------------------------------------------------------
71		signal aclk			: std_logic							:= '0';
72		signal aresetn		: std_logic							:= '0';
73		signal spi_sck		: std_logic							:= '0';
74		signal spi_cs_n		: std_logic_vector(SlaveCnt_c-1 downto 0)		:= (others => '0');
75		signal spi_mosi		: std_logic							:= '0';
76		signal spi_miso		: std_logic							:= '0';
77		signal spi_le		: std_logic_vector(SlaveCnt_c-1 downto 0)		:= (others => '0');
78	    signal irq			: std_logic							:= '0';
79	
80	begin
81	
82		-------------------------------------------------------------------------
83		-- DUT
84		-------------------------------------------------------------------------
85		i_dut : entity work.spi_vivado_wrp
86			generic map
87			(
88				-- Component Generics
89				ClockDivider_g	=> 20,
90				TransWidth_g	=> 8,
91				CsHighCycles_g	=> 50,
92				SpiCPOL_g		=> 0,
93				SpiCPHA_g		=> 0,
94				SlaveCnt_g		=> SlaveCnt_c,
95				LsbFirst_g		=> false,
96				FifoDepth_g		=> 8,
97				-- AXI
98				C_S00_AXI_ID_WIDTH     	 	=> ID_WIDTH
99			)
100			port map
101			(
102				-- Clocks
103				spi_sck				=> spi_sck,
104				spi_cs_n			=> spi_cs_n,
105				spi_mosi			=> spi_mosi,
106				spi_miso 			=> spi_miso,
107	            spi_le              => spi_le,
108				irq					=> irq,
109				-- Axi Slave Bus Interface
110				s00_axi_aclk    	=> aclk,
111				s00_axi_aresetn  	=> aresetn,
112				s00_axi_arid        => axi_ms.arid,
113				s00_axi_araddr      => axi_ms.araddr,
114				s00_axi_arlen       => axi_ms.arlen,
115				s00_axi_arsize      => axi_ms.arsize,
116				s00_axi_arburst     => axi_ms.arburst,
117				s00_axi_arlock      => axi_ms.arlock,
118				s00_axi_arcache     => axi_ms.arcache,
119				s00_axi_arprot      => axi_ms.arprot,
120				s00_axi_arvalid     => axi_ms.arvalid,
121				s00_axi_arready     => axi_sm.arready,
122				s00_axi_rid         => axi_sm.rid,
123				s00_axi_rdata       => axi_sm.rdata,
124				s00_axi_rresp       => axi_sm.rresp,
125				s00_axi_rlast       => axi_sm.rlast,
126				s00_axi_rvalid      => axi_sm.rvalid,
127				s00_axi_rready      => axi_ms.rready,
128				s00_axi_awid    	=> axi_ms.awid,    
129				s00_axi_awaddr      => axi_ms.awaddr,
130				s00_axi_awlen       => axi_ms.awlen,
131				s00_axi_awsize      => axi_ms.awsize,
132				s00_axi_awburst     => axi_ms.awburst,
133				s00_axi_awlock      => axi_ms.awlock,
134				s00_axi_awcache     => axi_ms.awcache,
135				s00_axi_awprot      => axi_ms.awprot,
136				s00_axi_awvalid     => axi_ms.awvalid,
137				s00_axi_awready     => axi_sm.awready,
138				s00_axi_wdata       => axi_ms.wdata,
139				s00_axi_wstrb       => axi_ms.wstrb,
140				s00_axi_wlast       => axi_ms.wlast,
141				s00_axi_wvalid      => axi_ms.wvalid,
142				s00_axi_wready      => axi_sm.wready,
143				s00_axi_bid         => axi_sm.bid,
144				s00_axi_bresp       => axi_sm.bresp,
145				s00_axi_bvalid      => axi_sm.bvalid,
146				s00_axi_bready      => axi_ms.bready			
147			);
148		
149		-------------------------------------------------------------------------
150		-- Clock
151		-------------------------------------------------------------------------
152		p_aclk : process
153		begin
154			aclk <= '0';
155			while TbRunning loop
156				wait for 0.5*ClockPeriodAxi_c;
157				aclk <= '1';
158				wait for 0.5*ClockPeriodAxi_c;
159				aclk <= '0';
160			end loop;
161			wait;
162		end process;
163		
164		-------------------------------------------------------------------------
165		-- TB Control
166		-------------------------------------------------------------------------
167		p_control : process
168			variable Readback_v	: integer;
169			variable ReadbackSlv_v : std_logic_vector(31 downto 0);
170		begin
171			-- Reset
172			aresetn <= '0';
173			wait for 1 us;
174			wait until rising_edge(aclk);
175			aresetn <= '1';
176			wait for 1 us;
177			wait until rising_edge(aclk);
178			
179			-- *** Write Only Transaction ***
180			SlaveNr <= 1;
181			axi_single_write(RegIdx_SlaveNr_c*4, 1, axi_ms, axi_sm, aclk);		
182			ExpectedSlaveRx <= X"AB";
183			axi_single_write(RegIdx_StoreRx_c*4, 0, axi_ms, axi_sm, aclk);
184			axi_single_write(RegIdx_Data_c*4, 16#AB#, axi_ms, axi_sm, aclk);		
185			wait for 100 ns;
186			wait until rising_edge(aclk);
187			Readback_v := 1;
188			while Readback_v /= 0 loop
189				axi_single_read(RegIdx_Status_c*4, Readback_v, axi_ms, axi_sm, aclk,BitIdx_Status_Busy_c, BitIdx_Status_Busy_c);
190			end loop;
191			
192			-- *** Write/Read Transaction ***
193			SlaveNr <= 0;
194			axi_single_write(RegIdx_SlaveNr_c*4, 0, axi_ms, axi_sm, aclk);		
195			ExpectedSlaveRx <= X"12";
196			SlaveTx <= X"34";
197			axi_single_write(RegIdx_StoreRx_c*4, 1, axi_ms, axi_sm, aclk);
198			axi_single_write(RegIdx_Data_c*4, 16#12#, axi_ms, axi_sm, aclk);		
199			wait for 20 ns;
200			wait until rising_edge(aclk);
201			Readback_v := 1;
202			while Readback_v /= 0 loop
203				axi_single_read(RegIdx_Status_c*4, Readback_v, axi_ms, axi_sm, aclk,BitIdx_Status_Busy_c, BitIdx_Status_Busy_c);
204			end loop;	
205			axi_single_expect(RegIdx_Data_c*4, 16#34#, axi_ms, axi_sm, aclk, "Wrong Read Data", 7, 0); 
206			
207			-- *** Fill FIFO and check status, IRQ on every transfer ***
208			-- Setup IRQ on every transfer
209			wait until rising_edge(aclk);
210			wait until rising_edge(aclk);
211			wait until rising_edge(aclk);
212			axi_single_write(RegIdx_IrqVec_c*4, 16#FF#, axi_ms, axi_sm, aclk);	
213			axi_single_write(RegIdx_IrqEna_c*4, 2**Irq_TfDone_c, axi_ms, axi_sm, aclk);
214			axi_single_write(RegIdx_TxAlmEmptyLevel_c*4, 3, axi_ms, axi_sm, aclk);
215			axi_single_write(RegIdx_RxAlmFullLevel_c*4, 2, axi_ms, axi_sm, aclk);
216			-- Setup Transfers
217			SlaveNr <= 0;
218			axi_single_write(RegIdx_SlaveNr_c*4, 0, axi_ms, axi_sm, aclk);
219			SlaveTx <= std_logic_vector(to_unsigned(16#11#, 8));
220			ExpectedSlaveRx <= std_logic_vector(to_unsigned(16#01#, 8));
221			for i in 1 to 9 loop						
222				-- read/write only for every second transaction
223				axi_single_write(RegIdx_StoreRx_c*4, i mod 2, axi_ms, axi_sm, aclk);
224				axi_single_write(RegIdx_Data_c*4, i, axi_ms, axi_sm, aclk);	
225			end loop;
226			axi_single_write(RegIdx_IrqVec_c*4, 16#FF#, axi_ms, axi_sm, aclk);
227			-- Do Checks
228			for i in 1 to 9 loop
229				-- Status before TF Done
230				axi_single_expect(RegIdx_RxLevel_c*4, i/2, axi_ms, axi_sm, aclk, "RxLevel before", 7, 0); 
231				axi_single_expect(RegIdx_TxLevel_c*4, 9-i, axi_ms, axi_sm, aclk, "TxLevel before", 7, 0); 
232				axi_single_read(RegIdx_Status_c*4, Readback_v, axi_ms, axi_sm, aclk, 7, 0);
233				ReadbackSlv_v := std_logic_vector(to_signed(Readback_v, 32));
234				StdlCompare(choose(i=9, 1, 0), ReadbackSlv_v(BitIdx_Status_TxEmpty_c), "TxEmpty not correct before " & to_string(i));
235				StdlCompare(choose(i=1, 1, 0), ReadbackSlv_v(BitIdx_Status_TxFull_c), "TxFull not correct before " & to_string(i));
236				StdlCompare(choose(i>=9-3, 1, 0), ReadbackSlv_v(BitIdx_Status_TxAlmEmpty_c), "TxAlmEmpty not correct before " & to_string(i));
237				StdlCompare(1, ReadbackSlv_v(BitIdx_Status_Busy_c), "Busy not correct before " & to_string(i));
238				StdlCompare(0, ReadbackSlv_v(BitIdx_Status_RxFull_c), "RxFull not correct before " & to_string(i));
239				StdlCompare(choose(i>=4, 1, 0), ReadbackSlv_v(BitIdx_Status_RxAlmFull_c), "RxAlmFull not correct before " & to_string(i));
240				StdlCompare(choose(i=1, 1, 0), ReadbackSlv_v(BitIdx_Status_RxEmpty_c), "RxEmpty not correct before " & to_string(i));
241				axi_single_read(RegIdx_IrqVec_c*4, Readback_v, axi_ms, axi_sm, aclk, 7, 0);
242				ReadbackSlv_v := std_logic_vector(to_signed(Readback_v, 32));		
243				StdlCompare(choose(i=9, 1, 0), ReadbackSlv_v(Irq_TxEmpty_c), "Vec TxEmpty not correct before " & to_string(i)); 
244				StdlCompare(choose(i>=9-3, 1, 0), ReadbackSlv_v(Irq_TxAlmEmpty_c), "Vec TxAlmEmpty not correct before " & to_string(i));
245				StdlCompare(choose(i>=4, 1, 0), ReadbackSlv_v(Irq_RxAlmFull_c), "Vec RxAlmFull not correct before " & to_string(i));			
246				-- Expectations for next transfer
247				ExpectedSlaveRx <= std_logic_vector(to_unsigned(16#01#+i, 8));
248				SlaveTx <= std_logic_vector(to_unsigned(16#11#+i, 8));			
249				-- Wait for TF done
250				wait until rising_edge(aclk) and irq = '1';
251				axi_single_write(RegIdx_IrqVec_c*4, 16#FF#, axi_ms, axi_sm, aclk);	
252				wait for 20 ns;
253				wait until rising_edge(aclk); 			
254				-- Status after TF Done
255				axi_single_expect(RegIdx_RxLevel_c*4, (i+1)/2, axi_ms, axi_sm, aclk, "RxLevel after", 7, 0); 
256				axi_single_expect(RegIdx_TxLevel_c*4, max(9-i-1, 0), axi_ms, axi_sm, aclk, "TxLevel after", 7, 0);
257				axi_single_read(RegIdx_Status_c*4, Readback_v, axi_ms, axi_sm, aclk, 7, 0);
258				ReadbackSlv_v := std_logic_vector(to_signed(Readback_v, 32));
259				StdlCompare(choose(i>=8, 1, 0), ReadbackSlv_v(BitIdx_Status_TxEmpty_c), "TxEmpty not correct after " & to_string(i));
260				StdlCompare(0, ReadbackSlv_v(BitIdx_Status_TxFull_c), "TxFull not correct after " & to_string(i));
261				StdlCompare(choose(i>=8-3, 1, 0), ReadbackSlv_v(BitIdx_Status_TxAlmEmpty_c), "TxAlmEmpty not correct after " & to_string(i));
262				StdlCompare(choose(i=9, 0, 1), ReadbackSlv_v(BitIdx_Status_Busy_c), "Busy not correct after " & to_string(i));
263				StdlCompare(0, ReadbackSlv_v(BitIdx_Status_RxFull_c), "RxFull not correct after " & to_string(i));
264				StdlCompare(choose(i>=3, 1, 0), ReadbackSlv_v(BitIdx_Status_RxAlmFull_c), "RxAlmFull not correct after " & to_string(i));
265				StdlCompare(0, ReadbackSlv_v(BitIdx_Status_RxEmpty_c), "RxEmpty not correct after " & to_string(i));
266				axi_single_read(RegIdx_IrqVec_c*4, Readback_v, axi_ms, axi_sm, aclk, 7, 0);
267				ReadbackSlv_v := std_logic_vector(to_signed(Readback_v, 32));	
268				StdlCompare(choose(i>=8, 1, 0), ReadbackSlv_v(Irq_TxEmpty_c), "Vec TxEmpty not correct after " & to_string(i));
269				StdlCompare(choose(i>=8-3, 1, 0), ReadbackSlv_v(Irq_TxAlmEmpty_c), "Vec TxAlmEmpty not correct after " & to_string(i));
270				StdlCompare(choose(i>=3, 1, 0), ReadbackSlv_v(Irq_RxAlmFull_c), "Vec RxAlmFull not correct after " & to_string(i));			
271			end loop;		
272			-- Check RX Data
273			axi_single_expect(RegIdx_Data_c*4, 16#11#, axi_ms, axi_sm, aclk, "Wrong Read Data", 7, 0); 
274			axi_single_expect(RegIdx_Data_c*4, 16#13#, axi_ms, axi_sm, aclk, "Wrong Read Data", 7, 0); 
275			axi_single_expect(RegIdx_Data_c*4, 16#15#, axi_ms, axi_sm, aclk, "Wrong Read Data", 7, 0); 
276			axi_single_expect(RegIdx_Data_c*4, 16#17#, axi_ms, axi_sm, aclk, "Wrong Read Data", 7, 0); 
277			axi_single_expect(RegIdx_Data_c*4, 16#19#, axi_ms, axi_sm, aclk, "Wrong Read Data", 7, 0); 
278			
279			-- *** Test RX Full ***
280			SlaveNr <= 0;
281			axi_single_write(RegIdx_SlaveNr_c*4, 0, axi_ms, axi_sm, aclk);		
282			ExpectedSlaveRx <= X"12";
283			SlaveTx <= X"34";
284			axi_single_write(RegIdx_StoreRx_c*4, 1, axi_ms, axi_sm, aclk);
285			for i in 0 to 7 loop
286				axi_single_write(RegIdx_Data_c*4, 16#12#, axi_ms, axi_sm, aclk);		
287			end loop;
288			wait for 20 ns;
289			wait until rising_edge(aclk);
290			Readback_v := 1;
291			while Readback_v /= 0 loop
292				axi_single_read(RegIdx_Status_c*4, Readback_v, axi_ms, axi_sm, aclk,BitIdx_Status_Busy_c, BitIdx_Status_Busy_c);
293			end loop;
294			axi_single_expect(RegIdx_IrqVec_c*4, 1, axi_ms, axi_sm, aclk, "RX full IRQ not set", Irq_RxFull_c, Irq_RxFull_c); 	
295			axi_single_expect(RegIdx_Status_c*4, 1, axi_ms, axi_sm, aclk, "RX full status not set", BitIdx_Status_RxFull_c, BitIdx_Status_RxFull_c); 
296			axi_single_expect(RegIdx_Data_c*4, 16#34#, axi_ms, axi_sm, aclk, "Wrong Read Data", 7, 0); 
297			axi_single_expect(RegIdx_IrqVec_c*4, 1, axi_ms, axi_sm, aclk, "RX full IRQ not set after read", Irq_RxFull_c, Irq_RxFull_c); 	
298			axi_single_write(RegIdx_IrqVec_c*4, 2**Irq_RxFull_c, axi_ms, axi_sm, aclk);
299			axi_single_expect(RegIdx_IrqVec_c*4, 0, axi_ms, axi_sm, aclk, "RX full IRQ not cleared", Irq_RxFull_c, Irq_RxFull_c); 
300			axi_single_expect(RegIdx_Status_c*4, 0, axi_ms, axi_sm, aclk, "RX full status not cleared", BitIdx_Status_RxFull_c, BitIdx_Status_RxFull_c); 	
301			for i in 1 to 7 loop
302				axi_single_expect(RegIdx_Data_c*4, 16#34#, axi_ms, axi_sm, aclk, "Wrong Read Data", 7, 0); 		
303			end loop;
304			
305			-- *** Test IRQ clearing ***
306			-- Individual clearing of bits
307			axi_single_expect(RegIdx_IrqVec_c*4, 16#17#, axi_ms, axi_sm, aclk, "IRQ Vec has unexpected value before clearing", 7, 0); 
308			axi_single_write(RegIdx_IrqVec_c*4, 16#0C#, axi_ms, axi_sm, aclk);
309			axi_single_expect(RegIdx_IrqVec_c*4, 16#13#, axi_ms, axi_sm, aclk, "IRQ Vec has unexpected value after clearing", 7, 0); 
310			-- IRQs whoes condition is still valid are reset
311			axi_single_write(RegIdx_IrqVec_c*4, 16#02#, axi_ms, axi_sm, aclk);
312			axi_single_expect(RegIdx_IrqVec_c*4, 16#13#, axi_ms, axi_sm, aclk, "IRQ Vec has unexpected value after autoreset", 7, 0); 
313			
314			-- TB done
315			TbRunning <= false;
316			wait;
317		end process;
318		
319		-------------------------------------------------------------------------
320		-- SPI Emulation
321		-------------------------------------------------------------------------
322		p_spi : process
323			constant TransWidth_c 	: integer := 8;
324			constant SpiCPHA_c		: integer := 0;
325			constant SpiCPOL_c		: integer := 0;
326			constant LsbFirst_c		: boolean := false;
327			variable ShiftRegRx_v 	: std_logic_vector(TransWidth_c-1 downto 0);
328			variable ShiftRegTx_v 	: std_logic_vector(TransWidth_c-1 downto 0);
329			variable ExpLatch_v		: std_logic_vector(TransWidth_c-1 downto 0);
330		begin	
331			wait until aresetn = '1';
332			wait until rising_edge(aclk);
333			
334			while TbRunning loop
335				-- If start of transfer
336				if spi_cs_n /= OnesVector(SlaveCnt_c) then
337					ShiftRegTx_v := SlaveTx;
338					ShiftRegRx_v := (others => 'U');
339					ExpLatch_v := ExpectedSlaveRx;
340					
341					-- Check correct slave
342					for s in 0 to SlaveCnt_c-1 loop
343						if s = SlaveNr then
344							StdlCompare(0, spi_cs_n(s), "Slave " & to_string(s) & " not selected");
345						else
346							StdlCompare(1, spi_cs_n(s), "Slave " & to_string(s) & " selected wrongly");
347						end if;
348					end loop;
349					
350					-- loop over bits
351					for i in 0 to TransWidth_c-1 loop
352						-- Wait for apply edge 
353						if (SpiCPHA_c = 1) and (i /= TransWidth_c-1) then	
354							if SpiCPOL_c = 0 then
355								wait until rising_edge(spi_sck);
356							else
357								wait until falling_edge(spi_sck);
358							end if;
359						elsif (SpiCPHA_c = 0) and (i /= 0) then	
360							if SpiCPOL_c = 0 then
361								wait until falling_edge(spi_sck);
362							else
363								wait until rising_edge(spi_sck);
364							end if;					
365						end if;
366						-- Shift TX
367						if LsbFirst_c then
368							spi_miso <= ShiftRegTx_v(0);
369							ShiftRegTx_v := 'U' & ShiftRegTx_v(TransWidth_c-1 downto 1);
370						else
371							spi_miso <= ShiftRegTx_v(TransWidth_c-1);
372							ShiftRegTx_v := ShiftRegTx_v(TransWidth_c-2 downto 0) & 'U';
373						end if;					
374						-- Wait for transfer edge
375						if ((SpiCPOL_c = 0) and (SpiCPHA_c = 0)) or
376						   ((SpiCPOL_c = 1) and (SpiCPHA_c = 1)) then
377						    wait until rising_edge(spi_sck);
378						else
379							wait until falling_edge(spi_sck);
380						end if;
381						-- Shift RX
382						if LsbFirst_c then
383							ShiftRegRx_v := spi_mosi & ShiftRegRx_v(TransWidth_c-1 downto 1);
384						else
385							ShiftRegRx_v := ShiftRegRx_v(TransWidth_c-2 downto 0) & spi_mosi;
386						end if;
387					end loop;
388	                StdlvCompareStdlv(ZerosVector(SlaveCnt_c), spi_le, "LE is not low");
389					-- wait fir CS going high
390					wait until spi_cs_n = OnesVector(SlaveCnt_c);
391					StdlvCompareStdlv(to_uslv(2**SlaveNr,SlaveCnt_c), spi_le, "LE not high after transmission");
392	                StdlvCompareStdlv (ExpLatch_v, ShiftRegRx_v, "SPI slave received wrong data");
393				else
394					wait until rising_edge(aclk);
395				end if;
396			end loop;	
397			wait;
398		end process;
399		
400		
401	
402	end sim;
403

